@import url('/assets/font/index.css');

// 像素风格变量
:root {
	// 像素风格配色
	--vh-pixel-bg: #2d3436;
	--vh-pixel-text: #636e72;
	--vh-pixel-accent: #00cec9;
	--vh-pixel-secondary: #fd79a8;
	--vh-pixel-border: #b2bec3;
	--vh-pixel-shadow: #00000040;

	// 像素字体
	--vh-pixel-font: 'Press Start 2P', 'VT323', monospace;

	// 边框粗细
	--vh-pixel-border-thick: 4px;
	--vh-pixel-border-thin: 2px;

	// 阴影偏移
	--vh-pixel-shadow-offset: 4px;

	// 圆角（像素风格使用小圆角或无圆角）
	--vh-pixel-radius: 0;
}

* {
	-webkit-tap-highlight-color: transparent;
	scrollbar-width: none;
	-ms-overflow-style: none;
	text-decoration: none;
	outline: none;

	::-webkit-scrollbar {
		display: none;
	}
}

::selection,
::-webkit-selection {
	color: #fff;
	background: var(--vh-pixel-accent);
}

html {
	word-wrap: break-word;
	overflow-wrap: break-word;
	font-size: 16px;
	font-weight: 400;

	&>body {
		position: relative;
		box-sizing: border-box;
		display: flex;
		flex-direction: column;
		width: 100vw;
		height: max-content;
		color: var(--vh-pixel-text);
		font-family: var(--vh-pixel-font);
		font-weight: 400;
		cursor: url('/assets/images/pixel.cur'), default;
		overflow-x: hidden;

		&::before {
			content: "";
			position: fixed;
			left: 0;
			top: 0;
			width: 100vw;
			height: 100vh;
			background: var(--vh-pixel-bg);
			background-image:
				linear-gradient(45deg, var(--vh-pixel-border) 25%, transparent 25%, transparent 75%, var(--vh-pixel-border) 75%, var(--vh-pixel-border)),
				linear-gradient(45deg, var(--vh-pixel-border) 25%, transparent 25%, transparent 75%, var(--vh-pixel-border) 75%, var(--vh-pixel-border));
			background-size: 20px 20px;
			background-position: 0 0, 10px 10px;
			opacity: 0.1;
			z-index: -1;
		}

		&>footer {
			box-sizing: border-box;
			width: 100%;
			height: max-content;
		}
	}
}

pre,
code {
	font-family: 'Press Start 2P', monospace !important;
}

a {
	color: var(--vh-pixel-accent);
	text-decoration: none;
	position: relative;

	&::after {
		content: '';
		position: absolute;
		bottom: -2px;
		left: 0;
		width: 100%;
		height: var(--vh-pixel-border-thin);
		background-color: var(--vh-pixel-accent);
		transition: all 0.2s ease;
	}

	&:hover::after {
		height: var(--vh-pixel-border-thick);
		background-color: var(--vh-pixel-secondary);
	}
}

img {
	user-select: none;
	-webkit-user-drag: none;
	image-rendering: pixelated;
}

// 像素风格容器
.vh-pixel-box {
	position: relative;
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	transition: all 0.2s ease;
}

.vh-pixel-box:hover {
	transform: translate(-2px, -2px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 2px) calc(var(--vh-pixel-shadow-offset) + 2px) 0 0 var(--vh-pixel-shadow);
}

// 像素风格按钮
.vh-pixel-btn {
	position: relative;
	display: inline-block;
	padding: 0.5rem 1.5rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.75rem;
	font-weight: bold;
	color: #fff;
	background-color: var(--vh-pixel-accent);
	border: var(--vh-pixel-border-thin) solid #fff;
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
	cursor: pointer;
	transition: all 0.1s ease;
	text-transform: uppercase;
}

.vh-pixel-btn:hover {
	background-color: var(--vh-pixel-secondary);
	transform: translate(-2px, -2px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 2px) calc(var(--vh-pixel-shadow-offset) + 2px) 0 0 #000;
}

.vh-pixel-btn:active {
	transform: translate(2px, 2px);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
}

// 像素风格输入框
.vh-pixel-input {
	position: relative;
	width: 100%;
	padding: 0.75rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-text);
	background-color: var(--vh-pixel-bg);
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	box-shadow: inset 0 0 0 var(--vh-pixel-border-thin) #000;
	outline: none;
}

.vh-pixel-input:focus {
	border-color: var(--vh-pixel-accent);
}

// 像素风格滚动条
::-webkit-scrollbar {
	width: 16px;
	height: 16px;
}

::-webkit-scrollbar-track {
	background: var(--vh-pixel-bg);
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
}

::-webkit-scrollbar-thumb {
	background: var(--vh-pixel-accent);
	border: 2px solid var(--vh-pixel-bg);
}

::-webkit-scrollbar-thumb:hover {
	background: var(--vh-pixel-secondary);
}

// 像素风格标签
.vh-pixel-tag {
	display: inline-block;
	padding: 0.25rem 0.75rem;
	margin: 0.25rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.625rem;
	color: var(--vh-pixel-bg);
	background-color: var(--vh-pixel-accent);
	border: var(--vh-pixel-border-thin) solid #fff;
}

// 像素风格卡片
.vh-pixel-card {
	position: relative;
	padding: 1.5rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	transition: all 0.2s ease;
}

.vh-pixel-card:hover {
	transform: translateY(-4px);
	box-shadow: calc(var(--vh-pixel-shadow-offset) + 4px) calc(var(--vh-pixel-shadow-offset) + 4px) 0 0 var(--vh-pixel-shadow);
}

// 像素风格加载动画
.vh-pixel-loading {
	position: relative;
	display: flex;
	justify-content: center;
	align-items: center;
	gap: 8px;
}

.vh-pixel-loading span {
	display: block;
	width: 12px;
	height: 12px;
	background-color: var(--vh-pixel-accent);
	animation: pixel-loading 1s ease-in-out infinite;
}

.vh-pixel-loading span:nth-child(2) {
	animation-delay: 0.2s;
}

.vh-pixel-loading span:nth-child(3) {
	animation-delay: 0.4s;
}

@keyframes pixel-loading {
	0%, 100% {
		transform: scale(1);
	}
	50% {
		transform: scale(0);
	}
}

// 像素风格头像
.vh-pixel-avatar {
	position: relative;
	width: 64px;
	height: 64px;
	border: var(--vh-pixel-border-thick) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-accent);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 #000;
	image-rendering: pixelated;
}

// 像素风格分割线
.vh-pixel-divider {
	width: 100%;
	height: var(--vh-pixel-border-thick);
	background: repeating-linear-gradient(
		45deg,
		var(--vh-pixel-border),
		var(--vh-pixel-border) 2px,
		transparent 2px,
		transparent 8px
	);
	border: none;
}

// 像素风格标题
.vh-pixel-title {
	font-family: var(--vh-pixel-font);
	font-size: 1.5rem;
	font-weight: bold;
	color: var(--vh-pixel-accent);
	text-transform: uppercase;
	letter-spacing: 2px;
	line-height: 1.5;
	margin-bottom: 1rem;
}

// 像素风格文本
.vh-pixel-text {
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	line-height: 1.6;
	color: var(--vh-pixel-text);
}

// 像素风格列表
.vh-pixel-list {
	list-style: none;
	padding: 0;
	margin: 0;
}

.vh-pixel-list li {
	position: relative;
	padding-left: 2rem;
	margin-bottom: 0.5rem;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-text);
}

.vh-pixel-list li::before {
	content: '►';
	position: absolute;
	left: 0;
	color: var(--vh-pixel-accent);
}

// 像素风格代码块
.vh-pixel-code {
	font-family: 'Press Start 2P', monospace;
	font-size: 0.75rem;
	padding: 0.5rem;
	background-color: #000;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	color: #0f0;
}

// 像素风格警告框
.vh-pixel-warning {
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-secondary);
	background-color: rgba(253, 121, 168, 0.1);
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-secondary);
}

// 像素风格成功框
.vh-pixel-success {
	padding: 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-accent);
	background-color: rgba(0, 206, 201, 0.1);
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
	color: var(--vh-pixel-accent);
}

// 像素风格图片容器
.vh-pixel-image {
	position: relative;
	overflow: hidden;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	box-shadow: var(--vh-pixel-shadow-offset) var(--vh-pixel-shadow-offset) 0 0 var(--vh-pixel-shadow);
	image-rendering: pixelated;
}

.vh-pixel-image img {
	width: 100%;
	height: auto;
	image-rendering: pixelated;
	transition: transform 0.2s ease;
}

.vh-pixel-image:hover img {
	transform: scale(1.05);
}

// 像素风格表格
.vh-pixel-table {
	width: 100%;
	border-collapse: collapse;
	font-family: var(--vh-pixel-font);
	font-size: 0.875rem;
}

.vh-pixel-table th,
.vh-pixel-table td {
	padding: 0.75rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
}

.vh-pixel-table th {
	background-color: var(--vh-pixel-accent);
	color: var(--vh-pixel-bg);
}

.vh-pixel-table tr:nth-child(even) {
	background-color: rgba(0, 206, 201, 0.1);
}

// 像素风格导航
.vh-pixel-nav {
	display: flex;
	gap: 1rem;
	flex-wrap: wrap;
}

.vh-pixel-nav a {
	font-family: var(--vh-pixel-font);
	font-size: 0.75rem;
	padding: 0.5rem 1rem;
	border: var(--vh-pixel-border-thin) solid var(--vh-pixel-border);
	background-color: var(--vh-pixel-bg);
	color: var(--vh-pixel-text);
	text-decoration: none;
	transition: all 0.2s ease;
}

.vh-pixel-nav a:hover,
.vh-pixel-nav a.active {
	background-color: var(--vh-pixel-accent);
	color: var(--vh-pixel-bg);
	border-color: #fff;
}

// 像素风格响应式
@media screen and (max-width: 768px) {
	.vh-pixel-title {
		font-size: 1.25rem;
	}

	.vh-pixel-text {
		font-size: 0.8125rem;
	}

	.vh-pixel-btn {
		font-size: 0.6875rem;
		padding: 0.375rem 1rem;
	}

	.vh-pixel-card {
		padding: 1rem;
	}
}

// 动画效果
@keyframes pixel-fade-in {
	0% {
		opacity: 0;
		transform: translateY(10px);
	}
	100% {
		opacity: 1;
		transform: translateY(0);
	}
}

.vh-pixel-fade-in {
	animation: pixel-fade-in 0.3s ease-out;
}

@keyframes pixel-blink {
	0%, 100% {
		opacity: 1;
	}
	50% {
		opacity: 0.5;
	}
}

.vh-pixel-blink {
	animation: pixel-blink 1s ease-in-out infinite;
}

