  flex-wrap: wrap;
  justify-content: center;
}
.nav-link {
  display: inline-block;
  padding: 6px 12px;
  font-family: var(--pixel-font-title);
  font-size: 8px;
  color: var(--pixel-text-dim) !important;
  text-decoration: none;
  border: 2px solid transparent;
  text-transform: uppercase;
  letter-spacing: 1px;
  transition: all var(--pixel-transition);
  &:hover, &.active {
    color: var(--pixel-bg) !important;
    background: var(--pixel-primary);
    border-color: var(--pixel-border);
  }
}
.header-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}
.mobile-menu-btn {
  display: none;
  flex-direction: column;
  gap: 4px;
  padding: 8px;
  background: none;
  border: 2px solid var(--pixel-border);
  cursor: pointer;
  span {
    display: block;
    width: 20px;
    height: 3px;
    background: var(--pixel-text);
    transition: all 0.3s;
