      repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,0.05) 3px, rgba(0,0,0,0.05) 4px),
      repeating-linear-gradient(90deg, transparent, transparent 3px, rgba(0,0,0,0.05) 3px, rgba(0,0,0,0.05) 4px);
    pointer-events: none;
  }
}
.main-title {
  font-family: var(--pixel-font-title);
  font-size: 18px;
  color: var(--pixel-primary);
  text-shadow: 4px 4px 0 var(--pixel-shadow-color);
  margin-bottom: 1rem;
}
.main-subtitle {
  font-family: var(--pixel-font-body);
  font-size: 24px;
  color: var(--pixel-text-dim);
  min-height: 30px;
}
</style>

<script>
  const el = document.getElementById('main-typewriter');
  if (el) {
    const texts = ['欢迎来到像素小站 🎮', '8-Bit Life, Infinite Possibilities ✨', '复古游戏，现代技术 🕹️', '像素世界，无限可能 🌟'];
    let ti = 0, ci = 0, deleting = false;
    function tick() {
      const cur = texts[ti];
      if (deleting) { el.textContent = cur.substring(0, --ci); }
      else { el.textContent = cur.substring(0, ++ci); }
      let delay = deleting ? 50 : 120;
      if (!deleting && ci === cur.length) { delay = 2000; deleting = true; }
      else if (deleting && ci === 0) { deleting = false; ti = (ti + 1) % texts.length; delay = 500; }
      setTimeout(tick, delay);
    }
    tick();
  }
</script>

