import rss from '@astrojs/rss';
import { getCollection } from 'astro:content';
import { siteConfig } from '@/config';

export async function GET(context: any) {
  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
  allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
  return rss({
    title: siteConfig.title,
    description: siteConfig.description,
    site: context.site,
    items: allPosts.map(post => ({
      title: post.data.title,
      pubDate: post.data.date,
      description: post.data.description,
      link: `/article/${post.id}/`,
    })),
  });
}

const now = new Date();
const pad = (n: number) => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const title = process.argv[2] || '新文章';
const slug = title.replace(/[^\w\u4e00-\u9fff]+/g, '-').toLowerCase();

const frontmatter = `---
title: '${title}'
description: '${title}的描述'
date: ${dateStr}
tags: []
categories: []
toc: true
comment: true
reward: false
---

## ${title}

在这里开始写你的文章吧！
`;

const fs = require('fs');
const path = require('path');
const dir = path.join(__dirname, '..', 'src', 'content', 'blog');
const filePath = path.join(dir, `${slug}.md`);
fs.writeFileSync(filePath, frontmatter);
console.log(`✅ 文章已创建: ${filePath}`);

import { defineConfig } from 'astro/config';
import mdx from '@astrojs/mdx';
import sitemap from '@astrojs/sitemap';
import compress from '@playform/compress';
import remarkMath from 'remark-math';
import remarkDirective from 'remark-directive';
import rehypeKatex from 'rehype-katex';
import rehypeSlug from 'rehype-slug';
import { siteConfig } from './src/config';

export default defineConfig({
  site: siteConfig.site,
  integrations: [
    mdx(),
    sitemap(),
    compress(),
  ],
  markdown: {
    remarkPlugins: [remarkMath, remarkDirective],
    rehypePlugins: [rehypeKatex, rehypeSlug],
    shikiConfig: {
      theme: 'github-dark',
    },
  },
  vite: {
    resolve: {
      alias: {
        '@': './src',
      },
    },
  },
  build: {
    assets: 'vh_static',
  },
});

export async function GET() {
  const robotsTxt = `User-agent: *
Allow: /
Sitemap: https://pixel-astro-blog.github.io/sitemap-index.xml
`;
  return new Response(robotsTxt, {
    headers: { 'Content-Type': 'text/plain; charset=utf-8' },
  });
}

