const { title, description, cover, banner = false } = Astro.props;
---
<Layout title={title} description={description} cover={cover}>
  {banner && (
    <div class="home-banner" slot="before">
      <div class="banner-content">
        <h1 class="banner-title">{siteConfig.title}</h1>
        <p class="banner-subtitle" id="typewriter"></p>
      </div>
    </div>
  )}
  <div class="page-layout">
    <div class="page-main">
      <slot />
    </div>
    <Aside />
  </div>
</Layout>

<script is:inline>
  import { siteConfig } from '@/config';
  // 打字机效果
  const el = document.getElementById('typewriter');
  if (el) {
    const texts = siteConfig.typewriter;
    let textIndex = 0, charIndex = 0, isDeleting = false;
    function type() {
      const current = texts[textIndex];
      if (isDeleting) {
        el.textContent = current.substring(0, charIndex - 1);
        charIndex--;
      } else {
        el.textContent = current.substring(0, charIndex + 1);
        charIndex++;
      }
      let delay = isDeleting ? 50 : 100;
      if (!isDeleting && charIndex === current.length) {
        delay = 2000;
        isDeleting = true;
      } else if (isDeleting && charIndex === 0) {
        isDeleting = false;
        textIndex = (textIndex + 1) % texts.length;
        delay = 500;
      }
      setTimeout(type, delay);
    }
    type();
  }
</script>

