      </div>
      <div class="article-content"><Content /></div>
      <Copyright title={post.data.title} url={articleUrl} />
      {post.data.reward && <Reward />}
      <PrevNextArticle prev={prevPost ? { title: prevPost.data.title, slug: prevPost.id } : null} next={nextPost ? { title: nextPost.data.title, slug: nextPost.id } : null} />
