  .search-item { padding: 0.75rem; margin-bottom: 4px; border: 3px solid var(--pixel-dark); background: var(--pixel-bg);
    a { display: block; font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-accent); text-decoration: none; }
    p { font-size: 15px; color: var(--pixel-text-dim); margin-top: 4px; }
  }
}
</style>

<script>
  const btn = document.getElementById('search-btn'), modal = document.getElementById('search-modal'),
    overlay = document.getElementById('search-overlay'), input = document.getElementById('search-input') as HTMLInputElement,
    results = document.getElementById('search-results'), closeBtn = document.getElementById('search-close');
  let searchData: any[] = [];
  function openSearch() { modal?.classList.add('open'); setTimeout(() => input?.focus(), 100); }
  function closeSearch() { modal?.classList.remove('open'); input.value = ''; results!.innerHTML = '<div class="search-placeholder">输入关键词开始搜索</div>'; }
  btn?.addEventListener('click', openSearch); overlay?.addEventListener('click', closeSearch); closeBtn?.addEventListener('click', closeSearch);
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape') closeSearch(); });
  input?.addEventListener('input', async () => {
    const q = input.value.trim().toLowerCase();
    if (!q) { results!.innerHTML = '<div class="search-placeholder">输入关键词开始搜索</div>'; return; }
    if (!searchData.length) { try { const r = await fetch('/pixel-astro-blog/vh_static/search.json'); searchData = await r.json(); } catch { return; } }
    const f = searchData.filter(i => i.title.toLowerCase().includes(q) || i.content.toLowerCase().includes(q));
    results!.innerHTML = f.slice(0, 10).map(i => `<div class="search-item"><a href="${i.url}">${i.title}</a><p>${i.content.substring(0, 120)}...</p></div>`).join('') || '<div class="search-placeholder">没有找到相关文章</div>';
  });
</script>

