  background: var(--pixel-bg-grid); border: 4px solid var(--pixel-dark);
  box-shadow: 6px 6px 0 0 var(--pixel-dark); padding: 1.5rem;
  transition: all 0.15s ease;
  &:hover { transform: translate(-2px, -2px); box-shadow: 8px 8px 0 0 var(--pixel-dark); }
}
