---
import PageLayout from '@/layouts/PageLayout/PageLayout.astro';
---
<PageLayout title="留言板">
  <div class="message-board">
    <h1 class="pixel-page-title">✉️ 留言板</h1>

    <div class="message-intro pixel-card">
      <div class="intro-icon">🎮</div>
      <div class="intro-content">
        <h3>欢迎来到像素小站的留言板！</h3>
        <p>有什么想说的，尽管留言吧！⚠️ 请友善交流，保持像素世界的和平！</p>
      </div>
    </div>

    <!-- 留言输入区 -->
    <div class="message-form pixel-card">
      <h3 class="form-title pixel-font">✏️ 写留言</h3>
      <div class="form-grid">
        <div class="form-field">
          <label class="field-label pixel-font">昵称</label>
          <input type="text" class="pixel-input" id="msg-name" placeholder="冒险者名字..." maxlength="20" />
        </div>
        <div class="form-field">
          <label class="field-label pixel-font">邮箱</label>
          <input type="email" class="pixel-input" id="msg-email" placeholder="your@email.com" />
        </div>
      </div>
      <div class="form-field full">
        <label class="field-label pixel-font">内容</label>
        <textarea class="pixel-input pixel-textarea" id="msg-content" placeholder="说点什么吧..." rows="4" maxlength="500"></textarea>
        <span class="char-count"><span id="char-num">0</span>/500</span>
      </div>
      <div class="form-actions">
        <div class="mood-picker">
          <span class="mood-label pixel-font">心情</span>
          <button class="mood-btn active" data-mood="😊">😊</button>
          <button class="mood-btn" data-mood="🎮">🎮</button>
          <button class="mood-btn" data-mood="🔥">🔥</button>
          <button class="mood-btn" data-mood="💡">💡</button>
          <button class="mood-btn" data-mood="❤️">❤️</button>
          <button class="mood-btn" data-mood="🤔">🤔</button>
          <button class="mood-btn" data-mood="🎉">🎉</button>
          <button class="mood-btn" data-mood="😴">😴</button>
        </div>
        <button class="pixel-btn submit-btn" id="msg-submit">📤 提交留言</button>
      </div>
    </div>

    <!-- 留言统计 -->
    <div class="message-stats pixel-card">
      <div class="stat-item"><span class="stat-icon">💬</span><span class="stat-num accent" id="total-msg">0</span><span class="stat-label">条留言</span></div>
      <div class="stat-item"><span class="stat-icon">🌟</span><span class="stat-num secondary" id="today-msg">0</span><span class="stat-label">今日新增</span></div>
      <div class="stat-item"><span class="stat-icon">👤</span><span class="stat-num purple" id="total-users">0</span><span class="stat-label">位冒险者</span></div>
    </div>

    <!-- 留言列表 -->
    <div class="message-list" id="message-list">
      <div class="empty-state pixel-card" id="empty-state">
        <div class="empty-icon">📬</div>
        <p class="pixel-font">NO MESSAGE YET!</p>
        <p>成为第一个留言的冒险者吧！</p>
      </div>
    </div>

    <!-- 留言模板（隐藏） -->
    <template id="msg-template">
      <div class="message-item pixel-card">
        <div class="msg-header">
          <div class="msg-avatar" data-color="0"></div>
          <div class="msg-user-info">
            <span class="msg-name"></span>
            <span class="msg-time"></span>
          </div>
          <span class="msg-mood"></span>
        </div>
        <div class="msg-body"></div>
        <div class="msg-footer">
          <button class="pixel-btn like-btn" data-likes="0">❤️ <span class="like-count">0</span></button>
          <button class="pixel-btn reply-btn">💬 回复</button>
        </div>
      </div>
    </template>
  </div>
</PageLayout>

<style lang="less">
.pixel-page-title { font-family: var(--pixel-font-title); font-size: 16px; color: var(--pixel-dark); text-shadow: 3px 3px 0 var(--pixel-shadow-color); margin-bottom: 1.5rem; }
.message-board { display: flex; flex-direction: column; gap: 1.5rem; }
.message-intro { display: flex; align-items: flex-start; gap: 1rem; padding: 1.25rem; }
.intro-icon { font-size: 32px; flex-shrink: 0; }
.intro-content { h3 { font-size: 18px; color: var(--pixel-dark); margin-bottom: 6px; } p { font-size: 15px; color: var(--pixel-text-dim); line-height: 1.6; } }

.message-form { padding: 1.5rem; }
.form-title { font-size: 11px; color: var(--pixel-dark); margin-bottom: 1rem; }
.form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; @media (max-width: 600px) { grid-template-columns: 1fr; } }
.form-field { display: flex; flex-direction: column; gap: 6px; &.full { margin-top: 1rem; } }
.field-label { font-size: 9px; color: var(--pixel-text-dim); }
.pixel-input { font-family: var(--pixel-font-body); font-size: 16px; padding: 10px 12px; background: var(--pixel-bg); border: 3px solid var(--pixel-dark); box-shadow: 3px 3px 0 0 var(--pixel-dark); color: var(--pixel-dark); outline: none; transition: all 0.15s;
  &:focus { border-color: var(--pixel-accent); box-shadow: 4px 4px 0 0 var(--pixel-accent); }
  &::placeholder { color: rgba(26,26,46,0.3); }
}
.pixel-textarea { resize: vertical; min-height: 100px; }
.char-count { font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-text-dim); text-align: right; margin-top: 4px; }

.form-actions { display: flex; align-items: center; justify-content: space-between; margin-top: 1rem; flex-wrap: wrap; gap: 1rem; }
.mood-picker { display: flex; align-items: center; gap: 4px; flex-wrap: wrap; }
.mood-label { font-size: 9px; color: var(--pixel-text-dim); margin-right: 4px; }
.mood-btn {
  width: 32px; height: 32px; font-size: 18px; border: 2px solid var(--pixel-dark);
  background: var(--pixel-bg); cursor: pointer; transition: all 0.15s; padding: 0;
  &:hover { transform: scale(1.2); }
  &.active { border-width: 3px; box-shadow: 2px 2px 0 0 var(--pixel-dark); background: var(--pixel-yellow); }
}
.submit-btn { background: var(--pixel-accent); color: white; font-family: var(--pixel-font-body); font-size: 16px; font-weight: bold;
  &:hover { transform: translate(-1px, -1px); box-shadow: 5px 5px 0 0 var(--pixel-dark); }
  &:active { transform: translate(3px, 3px); box-shadow: 0 0 0 0 var(--pixel-dark); }
}

.message-stats { display: flex; justify-content: center; gap: 2rem; padding: 1rem; }
.stat-item { text-align: center; }
.stat-icon { font-size: 20px; display: block; margin-bottom: 4px; }
.stat-num { font-family: var(--pixel-font-title); font-size: 18px; display: block; &.accent { color: var(--pixel-accent); } &.secondary { color: var(--pixel-secondary); } &.purple { color: var(--pixel-purple); } }
.stat-label { font-size: 12px; color: var(--pixel-text-dim); }

.message-list { display: flex; flex-direction: column; gap: 1rem; }
.empty-state { text-align: center; padding: 3rem 1.5rem; }
.empty-icon { font-size: 48px; margin-bottom: 1rem; }
.empty-state .pixel-font { font-size: 12px; color: var(--pixel-accent); margin-bottom: 8px; }
.empty-state p:last-child { font-size: 15px; color: var(--pixel-text-dim); }

.message-item { padding: 1.25rem; animation: msg-in 0.3s ease-out; }
@keyframes msg-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
.msg-header { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
.msg-avatar {
  width: 36px; height: 36px; border: 3px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark);
  display: flex; align-items: center; justify-content: center; color: white; font-family: var(--pixel-font-title); font-size: 12px;
}
.msg-user-info { flex: 1; }
.msg-name { font-weight: bold; font-size: 16px; color: var(--pixel-dark); display: block; }
.msg-time { font-size: 12px; color: var(--pixel-text-dim); font-family: var(--pixel-font-title); font-size: 9px; }
.msg-mood { font-size: 24px; }
.msg-body { font-size: 16px; line-height: 1.7; color: var(--pixel-dark); padding: 10px 0; border-top: 2px dashed rgba(26,26,46,0.15); border-bottom: 2px dashed rgba(26,26,46,0.15); word-break: break-word; }
.msg-footer { display: flex; gap: 8px; margin-top: 10px; }
.like-btn, .reply-btn {
  padding: 4px 10px; font-size: 13px; background: var(--pixel-bg); color: var(--pixel-dark);
  border: 2px solid var(--pixel-dark); box-shadow: 2px 2px 0 0 var(--pixel-dark); cursor: pointer; transition: all 0.15s;
  &:hover { transform: translate(-1px, -1px); box-shadow: 3px 3px 0 0 var(--pixel-dark); }
}
.like-btn.liked { background: var(--pixel-accent); color: white; border-color: var(--pixel-accent); }
</style>

<script define:vars={{ STORAGE_KEY: 'pixel-blog-messages' }}>
  const avatarColors = ['#e74c3c','#27ae60','#3498db','#9b59b6','#f39c12','#1abc9c','#e67e22','#2ecc71'];

  // 初始化
  const nameInput = document.getElementById('msg-name');
  const emailInput = document.getElementById('msg-email');
  const contentInput = document.getElementById('msg-content');
  const charNum = document.getElementById('char-num');
  const submitBtn = document.getElementById('msg-submit');
  const messageList = document.getElementById('message-list');
  const emptyState = document.getElementById('empty-state');
  const moodBtns = document.querySelectorAll('.mood-btn');
  let selectedMood = '😊';

  // 从 localStorage 加载留言
  function loadMessages() {
    try { return JSON.parse(localStorage.getItem('pixel-blog-messages') || '[]'); } catch { return []; }
  }
  function saveMessages(msgs) { localStorage.setItem('pixel-blog-messages', JSON.stringify(msgs)); }

  // 字数统计
  contentInput.addEventListener('input', () => { charNum.textContent = contentInput.value.length; });

  // 心情选择
  moodBtns.forEach(btn => {
    btn.addEventListener('click', () => {
      moodBtns.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      selectedMood = btn.dataset.mood;
    });
  });

  // 渲染留言
  function renderMessages() {
    const msgs = loadMessages();
    document.getElementById('total-msg').textContent = msgs.length;
    const today = new Date().toDateString();
    document.getElementById('today-msg').textContent = msgs.filter(m => new Date(m.time).toDateString() === today).length;
    const users = new Set(msgs.map(m => m.name));
    document.getElementById('total-users').textContent = users.size;

    if (msgs.length === 0) { emptyState.style.display = ''; return; }
    emptyState.style.display = 'none';

    // 清空已有留言DOM
    messageList.querySelectorAll('.message-item').forEach(el => el.remove());

    msgs.slice().reverse().forEach((msg, idx) => {
      const tpl = document.getElementById('msg-template');
      const el = tpl.content.cloneNode(true);
      const item = el.querySelector('.message-item');
      const colorIdx = msg.name.split('').reduce((a, c) => a + c.charCodeAt(0), 0) % avatarColors.length;
      item.querySelector('.msg-avatar').style.background = avatarColors[colorIdx];
      item.querySelector('.msg-avatar').textContent = msg.name.charAt(0).toUpperCase();
      item.querySelector('.msg-name').textContent = msg.name;
      item.querySelector('.msg-time').textContent = formatTime(msg.time);
      item.querySelector('.msg-mood').textContent = msg.mood;
      item.querySelector('.msg-body').textContent = msg.content;
      const likeBtn = item.querySelector('.like-btn');
      likeBtn.querySelector('.like-count').textContent = msg.likes || 0;
      if (msg.liked) likeBtn.classList.add('liked');
      likeBtn.addEventListener('click', () => {
        const allMsgs = loadMessages();
        const realIdx = allMsgs.length - 1 - idx;
        if (!allMsgs[realIdx].liked) { allMsgs[realIdx].likes = (allMsgs[realIdx].likes || 0) + 1; allMsgs[realIdx].liked = true; }
        else { allMsgs[realIdx].likes = Math.max(0, (allMsgs[realIdx].likes || 0) - 1); allMsgs[realIdx].liked = false; }
        saveMessages(allMsgs); renderMessages();
      });
      messageList.appendChild(el);
    });
  }

  function formatTime(ts) {
    const d = new Date(ts), now = new Date(), diff = now - d;
    if (diff < 60000) return '刚刚';
    if (diff < 3600000) return Math.floor(diff / 60000) + '分钟前';
    if (diff < 86400000) return Math.floor(diff / 3600000) + '小时前';
    return d.toLocaleDateString('zh-CN') + ' ' + d.toLocaleTimeString('zh-CN', {hour:'2-digit',minute:'2-digit'});
  }

  // 提交留言
  submitBtn.addEventListener('click', () => {
    const name = nameInput.value.trim() || '匿名冒险者';
    const email = emailInput.value.trim();
    const content = contentInput.value.trim();
    if (!content) { contentInput.style.borderColor = 'var(--pixel-accent)'; contentInput.focus(); return; }
    const msgs = loadMessages();
    msgs.push({ name, email, content, mood: selectedMood, time: Date.now(), likes: 0, liked: false });
    saveMessages(msgs);
    nameInput.value = ''; emailInput.value = ''; contentInput.value = ''; charNum.textContent = '0';
    renderMessages();
    // 滚动到最新留言
    messageList.scrollIntoView({ behavior: 'smooth', block: 'end' });
  });

  // 恢复用户名
  const savedName = localStorage.getItem('pixel-blog-username');
  if (savedName) nameInput.value = savedName;
  nameInput.addEventListener('blur', () => { if (nameInput.value.trim()) localStorage.setItem('pixel-blog-username', nameInput.value.trim()); });

  // 初始渲染
  renderMessages();

  // 预置一些示例留言
  if (loadMessages().length === 0) {
    const demoMsgs = [
      { name: '像素骑士', email: '', content: '这个像素风博客太酷了！🎮 感觉回到了8-bit时代！', mood: '🎮', time: Date.now() - 3600000 * 2, likes: 5, liked: false },
      { name: '代码法师', email: '', content: 'Astro + 像素风 = 完美组合！页面加载速度超快，样式也很有个性。', mood: '🔥', time: Date.now() - 86400000, likes: 3, liked: false },
      { name: '音乐旅人', email: '', content: '音乐播放器功能不错，希望能加入更多8-bit风格的曲目！', mood: '😊', time: Date.now() - 86400000 * 3, likes: 2, liked: false },
    ];
    saveMessages(demoMsgs);
    renderMessages();
  }
</script>

