---
<div class="music-widget" id="music-widget">
  <div class="music-display">
    <div class="music-disc-wrap">
      <div class="music-disc" id="music-disc">♫</div>
    </div>
    <div class="music-info">
      <div class="music-title" id="music-title">8-Bit Adventure</div>
