  // 8-bit 音乐合成器 - 使用 Web Audio API
  class ChiptunePlayer {
    constructor() {
      this.ctx = null; this.playing = false; this.currentTrack = 0;
      this.volume = 0.6; this.startTime = 0; this.elapsed = 0;
      this.scheduledNodes = []; this.analyser = null;
      this.playlist = [
