        { name: 'Pixel Dreams', artist: 'Chiptune', tempo: 120, pattern: 'dreams' },
        { name: 'Retro Battle', artist: 'Chiptune', tempo: 160, pattern: 'battle' },
        { name: 'Night Code', artist: 'Chiptune', tempo: 100, pattern: 'night' },
      ];
      this.noteTimer = null; this.stepIndex = 0;
      this.patterns = this.buildPatterns();
    }

    init() {
      if (this.ctx) return;
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      this.gainNode = this.ctx.createGain();
      this.gainNode.gain.value = this.volume;
      this.analyser = this.ctx.createAnalyser();
      this.analyser.fftSize = 64;
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.ctx.destination);
    }

    buildPatterns() {
