          bass:  ['C3','C3','C3','C3','G3','G3','G3','G3','E3','E3','E3','E3','F3','F3','G3','G3','C3','C3','C3','C3','G3','G3','G3','G3','A3','A3','A3','A3','F3','F3','G3','C3'],
        },
