        },
        night: {
          melody: ['A4','REST','C5','REST','E5','D5','C5','A4','REST','G4','A4','REST','C5','REST','A4','G4','F4','REST','E4','REST','D4','E4','F4','A4','G4','REST','E4','REST','C4','REST','REST','REST'],
