<script define:vars={{ playlistJson, baseUrl: '/pixel-astro-blog' }}>
  const playlist = JSON.parse(playlistJson);
  const audio = document.getElementById('audio-player');
  const disc = document.getElementById('music-disc');
  const titleEl = document.getElementById('music-title');
  const subtitleEl = document.getElementById('music-subtitle');
  const timeCurrent = document.getElementById('time-current');
  const timeTotal = document.getElementById('time-total');
  const progressFill = document.getElementById('progress-fill');
  const progressBar = document.getElementById('progress-bar');
  const btnPlay = document.getElementById('btn-play');
  const btnPrev = document.getElementById('btn-prev');
  const btnNext = document.getElementById('btn-next');
  const btnLoop = document.getElementById('btn-loop');
  const volumeSlider = document.getElementById('volume-slider');
  const volumeIcon = document.getElementById('volume-icon');
  const playlistItems = document.querySelectorAll('.playlist-item');

  let currentIndex = 0;
  let isPlaying = false;
  let loopMode = 'all'; // all, one, none
  const loopModes = ['all', 'one', 'none'];
  const loopIcons = { all: '🔁', one: '🔂', none: '➡️' };

  function formatTime(s) {
    if (isNaN(s)) return '0:00';
    const m = Math.floor(s / 60), sec = Math.floor(s % 60);
    return m + ':' + (sec < 10 ? '0' : '') + sec;
  }

  function loadTrack(index) {
    currentIndex = index;
    const track = playlist[index];
    audio.src = track.src;
    audio.load();
    titleEl.textContent = track.emoji + ' ' + track.title;
    subtitleEl.textContent = track.subtitle + ' (' + track.year + ')';
    playlistItems.forEach((el, i) => el.classList.toggle('active', i === index));
  }

  function togglePlay() {
    if (isPlaying) {
      audio.pause();
      disc.classList.remove('spinning');
      btnPlay.textContent = '▶';
      isPlaying = false;
    } else {
      if (!audio.src || audio.src === '') loadTrack(currentIndex);
      audio.play().catch(() => {});
      disc.classList.add('spinning');
      btnPlay.textContent = '⏸';
      isPlaying = true;
    }
  }

  function nextTrack() {
    if (loopMode === 'one') { audio.currentTime = 0; audio.play(); return; }
    currentIndex = (currentIndex + 1) % playlist.length;
    loadTrack(currentIndex);
    if (isPlaying) audio.play().catch(() => {});
  }

  function prevTrack() {
    if (audio.currentTime > 3) { audio.currentTime = 0; return; }
    currentIndex = (currentIndex - 1 + playlist.length) % playlist.length;
    loadTrack(currentIndex);
    if (isPlaying) audio.play().catch(() => {});
  }

  audio.addEventListener('timeupdate', () => {
    if (audio.duration) {
      const pct = (audio.currentTime / audio.duration) * 100;
      progressFill.style.width = pct + '%';
      timeCurrent.textContent = formatTime(audio.currentTime);
      timeTotal.textContent = formatTime(audio.duration);
    }
  });

  audio.addEventListener('ended', () => {
    if (loopMode === 'one') { audio.currentTime = 0; audio.play(); }
    else if (loopMode === 'all' || currentIndex < playlist.length - 1) { nextTrack(); }
    else { isPlaying = false; btnPlay.textContent = '▶'; disc.classList.remove('spinning'); }
  });

  progressBar.addEventListener('click', (e) => {
    const rect = progressBar.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    if (audio.duration) audio.currentTime = pct * audio.duration;
  });

  btnPlay.addEventListener('click', togglePlay);
  btnNext.addEventListener('click', nextTrack);
  btnPrev.addEventListener('click', prevTrack);

  btnLoop.addEventListener('click', () => {
    const idx = (loopModes.indexOf(loopMode) + 1) % loopModes.length;
    loopMode = loopModes[idx];
    btnLoop.textContent = loopIcons[loopMode];
    btnLoop.classList.toggle('active', loopMode !== 'none');
  });

  volumeSlider.addEventListener('input', () => {
    audio.volume = volumeSlider.value / 100;
    volumeIcon.textContent = audio.volume === 0 ? '🔇' : audio.volume < 0.4 ? '🔉' : '🔊';
  });
  audio.volume = 0.6;

  volumeIcon.addEventListener('click', () => {
    if (audio.volume > 0) { audio._prevVol = audio.volume; audio.volume = 0; volumeSlider.value = 0; volumeIcon.textContent = '🔇'; }
    else { audio.volume = audio._prevVol || 0.6; volumeSlider.value = audio.volume * 100; volumeIcon.textContent = '🔊'; }
  });

  playlistItems.forEach((el, i) => {
    el.addEventListener('click', () => {
      loadTrack(i);
      audio.play().then(() => { isPlaying = true; btnPlay.textContent = '⏸'; disc.classList.add('spinning'); }).catch(() => {});
    });
  });

  // Auto-load first track info
  loadTrack(0);
</script>

