---
import Layout from '@/layouts/Layout/Layout.astro';
import { getCollection } from 'astro:content';
import { getReadingTime, getWordCount, formatDate } from '@/utils';
import { withBase } from '@/utils/path';
import { slugify } from '@/utils/slug';
import Copyright from '@/components/Copyright/Copyright.astro';
import PrevNextArticle from '@/components/PrevNextArticle/PrevNextArticle.astro';
import Comment from '@/components/Comment/Comment.astro';
import Reward from '@/components/Reward/Reward.astro';
import Aside from '@/components/Aside/Aside.astro';
import '@/styles/Article.less';

export async function getStaticPaths() {
  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
  return allPosts.map(post => ({ params: { article: slugify(post.id) }, props: { post } }));
}

const { post } = Astro.props;
const { Content } = await post.render();
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const ci = allPosts.findIndex(p => p.id === post.id);
const prevPost = ci > 0 ? allPosts[ci - 1] : null;
const nextPost = ci < allPosts.length - 1 ? allPosts[ci + 1] : null;
const slug = slugify(post.id);
const articleUrl = `https://3229154448.github.io/pixel-astro-blog/article/${slug}`;
---
<Layout title={post.data.title} description={post.data.description} cover={post.data.cover}>
  <div class="page-layout">
    <article class="article-detail pixel-card" style="padding: 0;">
      {post.data.cover && (
        <div class="article-cover">
          <img src={withBase(post.data.cover)} alt={post.data.title} />
          <div class="cover-overlay">
            <h1 class="cover-title">{post.data.title}</h1>
          </div>
        </div>
      )}
      <div class="article-body-wrap" style="padding: 2rem;">
        {!post.data.cover && <h1 class="article-title">{post.data.title}</h1>}
        <div class="article-meta">
          <span>📅 {formatDate(post.data.date)}</span>
          {post.data.updated && <span>🔄 {formatDate(post.data.updated)}</span>}
          <span>⏱️ {getReadingTime(post.body || '')} 分钟</span>
          <span>📝 {getWordCount(post.body || '')} 字</span>
        </div>
        <div class="article-tags">
          {post.data.tags.map((tag: string) => (
            <a href={withBase(`/tag/${tag}`)} class="pixel-tag">{tag}</a>
          ))}
        </div>
        <hr class="pixel-divider" />
        <div class="article-content"><Content /></div>
        <Copyright title={post.data.title} url={articleUrl} />
        {post.data.reward && <Reward />}
        <PrevNextArticle prev={prevPost ? { title: prevPost.data.title, slug: slugify(prevPost.id) } : null} next={nextPost ? { title: nextPost.data.title, slug: slugify(nextPost.id) } : null} />
        {post.data.comment && <Comment />}
      </div>
    </article>
    <Aside />
  </div>
</Layout>

<style lang="less">
.page-layout { display: flex; gap: 1.5rem; width: 100%; }
.article-cover {
  position: relative; overflow: hidden; border-bottom: 4px solid var(--pixel-dark);
  img { width: 100%; height: 280px; object-fit: cover; image-rendering: auto; }
}
.cover-overlay {
  position: absolute; bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, rgba(26,26,46,0.85), transparent);
  padding: 2rem 2rem 1.5rem;
}
.cover-title {
  font-family: var(--pixel-font-title); font-size: 14px; color: white;
  text-shadow: 3px 3px 0 var(--pixel-dark); line-height: 1.6;
}
@media (max-width: 768px) { .page-layout { flex-direction: column; } }
</style>

---
import { withBase } from '@/utils/path';
interface Props { prev?: { title: string; slug: string } | null; next?: { title: string; slug: string } | null; }
const { prev, next } = Astro.props;
---
<div class="prev-next">
  {prev && <a href={withBase(`/article/${prev.slug}`)} class="prev-next-item pixel-card"><span class="pn-label">◄ 上一篇</span><span class="pn-title">{prev.title}</span></a>}
  {next && <a href={withBase(`/article/${next.slug}`)} class="prev-next-item pixel-card"><span class="pn-label">下一篇 ►</span><span class="pn-title">{next.title}</span></a>}
</div>

<style lang="less">
.prev-next { display: flex; gap: 1rem; margin-top: 2rem; @media (max-width: 768px) { flex-direction: column; } }
.prev-next-item {
  flex: 1; padding: 1.25rem; text-decoration: none; color: var(--pixel-dark);
  display: flex; flex-direction: column; gap: 8px;
  &:hover { transform: translate(-2px, -2px); }
  &:hover .pn-title { color: var(--pixel-accent); }
}
.pn-label { font-family: var(--pixel-font-title); font-size: 9px; color: var(--pixel-text-dim); }
.pn-title { font-size: 16px; font-weight: bold; transition: color 0.2s; }
</style>

