arguments.content:
---
import { siteConfig } from '@/config';
import { withBase } from '@/utils/path';
import { getCollection } from 'astro:content';
import { slugify } from '@/utils/slug';

const allPosts = await getCollection('blog', ({ data }) => !data.draft);
const categories = [...new Set(allPosts.flatMap(p => p.data.categories))];
const tags = [...new Set(allPosts.flatMap(p => p.data.tags))];
---
<aside class="mobile-sidebar" id="mobile-sidebar">
  <div class="mobile-header">
    <span class="pixel-font">MENU</span>
    <button class="pixel-btn close-btn" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">✕</button>
  </div>

  <!-- 个人信息 -->
  <div class="mobile-profile">
    <img src={withBase('/assets/images/avatar-default.webp')} alt={siteConfig.author} class="mobile-avatar" width="64" height="64" />
    <h3 class="mobile-name pixel-font">{siteConfig.author}</h3>
    <p class="mobile-motto">{siteConfig.motto}</p>
  </div>

  <!-- 导航 -->
  <nav class="mobile-nav">
    {siteConfig.navbar.map(item => (
      <a href={withBase(item.link)} class="mobile-nav-link" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">{item.name}</a>
    ))}
  </nav>

  <!-- 分类 -->
  <div class="mobile-section">
    <h4 class="mobile-section-title pixel-font">📁 分类</h4>
    {categories.map(cat => (
      <a href={withBase(`/categories/${cat}`)} class="mobile-cat" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">{cat}</a>
    ))}
  </div>

  <!-- 标签 -->
  <div class="mobile-section">
    <h4 class="mobile-section-title pixel-font">🏷️ 标签</h4>
    <div class="mobile-tags">
      {tags.map(tag => (
        <a href={withBase(`/tag/${tag}`)} class="mobile-tag" onclick="document.getElementById('mobile-sidebar').classList.remove('open')">{tag}</a>
      ))}
    </div>
  </div>
</aside>

<style lang="less">
.mobile-sidebar {
  position: fixed; top: 0; left: -100%; width: 300px; height: 100vh;
  background: var(--pixel-bg); border-right: 4px solid var(--pixel-dark);
  box-shadow: 6px 0 0 0 var(--pixel-dark); z-index: 99;
  transition: left 0.3s; overflow-y: auto;
  &.open { left: 0; }
}
.mobile-header {
  display: flex; justify-content: space-between; align-items: center;
  padding: 1rem 1.25rem; border-bottom: 4px solid var(--pixel-dark);
  background: var(--pixel-accent); color: white;
  .pixel-font { font-family: var(--pixel-font-title); font-size: 12px; }
}
.close-btn { padding: 6px 10px; background: var(--pixel-dark); color: white; font-size: 14px; }

.mobile-profile { text-align: center; padding: 1.25rem; border-bottom: 2px dashed rgba(26,26,46,0.15); }
.mobile-avatar { width: 64px; height: 64px; border: 3px solid var(--pixel-dark); box-shadow: 3px 3px 0 0 var(--pixel-dark); image-rendering: pixelated; }
.mobile-name { font-family: var(--pixel-font-title); font-size: 10px; color: var(--pixel-dark); margin: 8px 0 4px; }
.mobile-motto { font-size: 14px; color: var(--pixel-text-dim); }

.mobile-nav { padding: 1rem; display: flex; flex-direction: column; gap: 4px; border-bottom: 2px dashed rgba(26,26,46,0.15); }
.mobile-nav-link {
  display: block; padding: 10px 14px; font-family: var(--pixel-font-body);
  font-size: 17px; font-weight: bold; color: var(--pixel-dark); text-decoration: none;
  border: 2px solid transparent; transition: all 0.2s;
  &:hover { background: var(--pixel-bg-grid); border-color: var(--pixel-dark); color: var(--pixel-accent); }
}

.mobile-section { padding: 1rem; border-bottom: 2px dashed rgba(26,26,46,0.15); }
.mobile-section-title { font-size: 9px; color: var(--pixel-dark); margin-bottom: 8px; }
.mobile-cat {
  display: block; padding: 6px 12px; font-size: 15px; color: var(--pixel-dark);
  text-decoration: none; border-left: 3px solid var(--pixel-accent); margin-bottom: 2px;
  &:hover { color: var(--pixel-accent); }
}
.mobile-tags { display: flex; flex-wrap: wrap; gap: 6px; }
.mobile-tag {
  display: inline-block; padding: 3px 8px; font-size: 12px; font-weight: bold;
  color: var(--pixel-dark); background: var(--pixel-yellow); border: 2px solid var(--pixel-dark);
  box-shadow: 2px 2px 0 0 var(--pixel-dark); text-decoration: none;
  &:hover { background: var(--pixel-accent); color: white; }
}
</style>

---
interface Props { headings: { depth: number; slug: string; text: string }[] }
const { headings } = Astro.props;
const filtered = headings.filter(h => h.depth >= 2 && h.depth <= 4);
---
{filtered.length > 0 && (
  <nav class="toc" id="toc">
    <h3 class="toc-title pixel-font">📜 目录</h3>
    <ul class="toc-list">
      {filtered.map(h => (
        <li class:list={[`toc-h${h.depth}`]}>
          <a href={`#${h.slug}`} class="toc-link" data-slug={h.slug}>{h.text}</a>
        </li>
      ))}
    </ul>
  </nav>
)}

<style lang="less">
.toc {
  position: sticky; top: 80px; max-height: calc(100vh - 100px); overflow-y: auto;
  background: var(--pixel-bg-grid); border: 4px solid var(--pixel-dark);
  box-shadow: 6px 6px 0 0 var(--pixel-dark); padding: 1rem; min-width: 200px;
  max-width: 260px; align-self: flex-start;
}
.toc-title { font-size: 10px; color: var(--pixel-dark); margin-bottom: 0.75rem; padding-bottom: 0.5rem; border-bottom: 2px dashed var(--pixel-dark); }
.toc-list { list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 2px; }
.toc-link {
  display: block; padding: 4px 8px; font-size: 14px; color: var(--pixel-text-dim);
  text-decoration: none; border-left: 3px solid transparent; transition: all 0.15s;
  &:hover { color: var(--pixel-accent); border-left-color: var(--pixel-accent); }
  &.active { color: var(--pixel-accent); border-left-color: var(--pixel-accent); background: rgba(231,76,60,0.1); font-weight: bold; }
}
.toc-h2 .toc-link { padding-left: 8px; }
.toc-h3 .toc-link { padding-left: 16px; font-size: 13px; }
.toc-h4 .toc-link { padding-left: 24px; font-size: 12px; }
</style>

<script>
  const tocLinks = document.querySelectorAll('.toc-link');
  const headings = document.querySelectorAll('h2[id], h3[id], h4[id]');

  function updateActive() {
    let current = '';
    headings.forEach(h => {
      const rect = h.getBoundingClientRect();
      if (rect.top <= 120) current = h.id;
    });
    tocLinks.forEach(link => {
      link.classList.toggle('active', link.getAttribute('data-slug') === current);
    });
  }

  window.addEventListener('scroll', updateActive, { passive: true });
  updateActive();
</script>

---
import Layout from '@/layouts/Layout/Layout.astro';
import { getCollection } from 'astro:content';
import { getReadingTime, getWordCount, formatDate } from '@/utils';
import { withBase } from '@/utils/path';
import { slugify } from '@/utils/slug';
import Copyright from '@/components/Copyright/Copyright.astro';
import PrevNextArticle from '@/components/PrevNextArticle/PrevNextArticle.astro';
import Comment from '@/components/Comment/Comment.astro';
import Reward from '@/components/Reward/Reward.astro';
import Aside from '@/components/Aside/Aside.astro';
import TOC from '@/components/TOC/TOC.astro';
import '@/styles/Article.less';

export async function getStaticPaths() {
  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
  return allPosts.map(post => ({ params: { article: slugify(post.id) }, props: { post } }));
}

const { post } = Astro.props;
const { Content, headings } = await post.render();
const allPosts = await getCollection('blog', ({ data }) => !data.draft);
allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
const ci = allPosts.findIndex(p => p.id === post.id);
const prevPost = ci > 0 ? allPosts[ci - 1] : null;
const nextPost = ci < allPosts.length - 1 ? allPosts[ci + 1] : null;
const slug = slugify(post.id);
const articleUrl = `https://3229154448.github.io/pixel-astro-blog/article/${slug}`;
const tocHeadings = headings.filter((h: any) => h.depth >= 2 && h.depth <= 4);
---
<Layout title={post.data.title} description={post.data.description} cover={post.data.cover}>
  <div class="page-layout">
    <article class="article-detail pixel-card" style="padding: 0;">
      {post.data.cover && (
        <div class="article-cover">
          <img src={withBase(post.data.cover)} alt={post.data.title} />
          <div class="cover-overlay">
            <h1 class="cover-title">{post.data.title}</h1>
          </div>
        </div>
      )}
      <div class="article-body-wrap" style="padding: 2rem;">
        {!post.data.cover && <h1 class="article-title">{post.data.title}</h1>}
        <div class="article-meta">
          <span>📅 {formatDate(post.data.date)}</span>
          {post.data.updated && <span>🔄 {formatDate(post.data.updated)}</span>}
          <span>⏱️ {getReadingTime(post.body || '')} 分钟</span>
          <span>📝 {getWordCount(post.body || '')} 字</span>
        </div>
        <div class="article-tags">
          {post.data.tags.map((tag: string) => (
            <a href={withBase(`/tag/${tag}`)} class="pixel-tag">{tag}</a>
          ))}
        </div>
        <hr class="pixel-divider" />
        <div class="article-content"><Content /></div>
        <Copyright title={post.data.title} url={articleUrl} />
        {post.data.reward && <Reward />}
        <PrevNextArticle prev={prevPost ? { title: prevPost.data.title, slug: slugify(prevPost.id) } : null} next={nextPost ? { title: nextPost.data.title, slug: slugify(nextPost.id) } : null} />
        {post.data.comment && <Comment />}
      </div>
    </article>
    <div class="article-sidebar">
      {tocHeadings.length > 0 && <TOC headings={tocHeadings} />}
      <Aside />
    </div>
  </div>
</Layout>

<style lang="less">
.page-layout { display: flex; gap: 1.5rem; width: 100%; }
.article-sidebar { display: flex; flex-direction: column; gap: 1.5rem; }
.article-cover {
  position: relative; overflow: hidden; border-bottom: 4px solid var(--pixel-dark);
  img { width: 100%; height: 280px; object-fit: cover; image-rendering: auto; }
}
.cover-overlay {
  position: absolute; bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, rgba(26,26,46,0.85), transparent);
  padding: 2rem 2rem 1.5rem;
}
.cover-title {
  font-family: var(--pixel-font-title); font-size: 14px; color: white;
  text-shadow: 3px 3px 0 var(--pixel-dark); line-height: 1.6;
}
@media (max-width: 768px) {
  .page-layout { flex-direction: column; }
  .article-sidebar .toc { display: none; }
}
</style>

// 暗色主题 CSS 变量覆盖
:root[data-theme="dark"] {
  --pixel-bg: #1a1c2c;
  --pixel-bg-grid: #262b44;
  --pixel-dark: #e8e0d5;
  --pixel-card: #262b44;
  --pixel-border: #e8e0d5;
  --pixel-accent: #ff6b6b;
  --pixel-secondary: #5cdb95;
  --pixel-primary: #ff6b6b;
  --pixel-yellow: #ffd93d;
  --pixel-purple: #b19cd9;
  --pixel-green: #5cdb95;
  --pixel-blue: #64b5f6;
  --pixel-orange: #ffb74d;
  --pixel-pink: #f48fb1;
  --pixel-cyan: #4dd0e1;
  --pixel-text: #e8e0d5;
  --pixel-text-dim: #9e9eb8;
  --pixel-code-bg: #0d0f1a;
  --pixel-code-color: #5cdb95;
  --pixel-shadow-color: #e8e0d5;
  --vh-white-color: var(--pixel-bg);
  --vh-box-shadow: 6px 6px 0 0 rgba(232, 224, 213, 0.3);
  --vh-body-bg: var(--pixel-bg);

  // CRT 扫描线在暗色下更明显
  & > body::after {
    background: repeating-linear-gradient(
      0deg, transparent, transparent 2px, rgba(0, 255, 100, 0.03) 2px, rgba(0, 255, 100, 0.03) 4px
    ) !important;
  }

  // 像素网格在暗色下变绿
  & > body::before {
