import { withBase } from '@/utils/path';
interface Props { currentPage: number; totalPages: number; }
const { currentPage, totalPages } = Astro.props;
---
{totalPages > 1 && (
  <nav class="pagination">
    {currentPage > 1 && (
      <a href={withBase(currentPage === 2 ? '/page/2' : `/page/${currentPage - 1}`)} class="pixel-btn page-btn">◁</a>
    )}
    {currentPage <= 1 && <span class="pixel-btn page-btn disabled">◁</span>}
    {Array.from({ length: totalPages }, (_, i) => i + 1).map(page => (
      <a href={withBase(page === 1 ? '/' : `/page/${page}`)} class:list={['pixel-btn', 'page-btn', { active: page === currentPage }]}>
        {page}
      </a>
    ))}
    {currentPage < totalPages && (
      <a href={withBase(`/page/${currentPage + 1}`)} class="pixel-btn page-btn">▷</a>
    )}
    {currentPage >= totalPages && <span class="pixel-btn page-btn disabled">▷</span>}
  </nav>
)}

