import PageLayout from '@/layouts/PageLayout/PageLayout.astro';
import ArticleCard from '@/components/ArticleCard/ArticleCard.astro';
import { slugify } from '@/utils/slug';
import Pagination from '@/components/Pagination/Pagination.astro';
import MainHeader from '@/components/MainHeader/MainHeader.astro';
import { getCollection } from 'astro:content';
import { withBase } from '@/utils/path';
import { getReadingTime, getWordCount } from '@/utils';

export async function getStaticPaths({ paginate }: any) {
  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
  allPosts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
  return paginate(allPosts, { pageSize: 10 });
}

const { page } = Astro.props;
const isFirstPage = page.currentPage === 1;
---
<PageLayout title="首页">
  {isFirstPage && <MainHeader />}
  {!isFirstPage && <h1 class="pixel-page-title">📜 文章列表 - 第 {page.currentPage} 页</h1>}
  <div class="post-list">
    {page.data.map((post: any) => (
      <ArticleCard
        title={post.data.title}
        description={post.data.description}
        cover={post.data.cover}
        date={post.data.date}
        tags={post.data.tags}
        categories={post.data.categories}
        readingTime={getReadingTime(post.body || '')}
        wordCount={getWordCount(post.body || '')}
        link={withBase(`/article/${slugify(post.id)}`)}
        pin={post.data.pin}
      />
    ))}
  </div>
  <Pagination currentPage={page.currentPage} totalPages={page.lastPage} />
</PageLayout>

<style lang="less">
.post-list { display: flex; flex-direction: column; gap: 1.5rem; }
.pixel-page-title { font-family: var(--pixel-font-title); font-size: 16px; color: var(--pixel-dark); text-shadow: 3px 3px 0 var(--pixel-shadow-color); margin-bottom: 1.5rem; }
